import React, { useState, useEffect } from 'react';
import api, { formatCurrency } from '../../utils/api';
import { useToast } from '../../context/ToastContext';

const emptyForm = { productName: '', description: '', price: '', stockQuantity: '', categoryID: '', imageUrl: '', status: 'active' };

export default function AdminProductsPage() {
  const [products, setProducts] = useState([]);
  const [categories, setCategories] = useState([]);
  const [loading, setLoading] = useState(true);
  const [modal, setModal] = useState(null); // null | 'create' | product object
  const [form, setForm] = useState(emptyForm);
  const [search, setSearch] = useState('');
  const { addToast } = useToast();

  useEffect(() => { loadData(); }, []);

  const loadData = async () => {
    try {
      const [pRes, cRes] = await Promise.all([api.get('/products?limit=100'), api.get('/categories')]);
      setProducts(pRes.data.products);
      setCategories(cRes.data.categories);
    } catch { addToast('Không thể tải dữ liệu', 'error'); }
    finally { setLoading(false); }
  };

  const openCreate = () => { setForm(emptyForm); setModal('create'); };
  const openEdit = (p) => {
    setForm({ productName: p.productName, description: p.description || '', price: p.price, stockQuantity: p.stockQuantity, categoryID: p.categoryID || '', imageUrl: p.imageUrl || '', status: p.status });
    setModal(p);
  };

  const save = async () => {
    try {
      if (modal === 'create') {
        await api.post('/products', form);
        addToast('Tạo sản phẩm thành công!', 'success');
      } else {
        await api.put(`/products/${modal.productID}`, form);
        addToast('Cập nhật sản phẩm thành công!', 'success');
      }
      setModal(null);
      loadData();
    } catch (err) { addToast(err.response?.data?.message || 'Lỗi', 'error'); }
  };

  const deleteProduct = async (id) => {
    if (!window.confirm('Vô hiệu hóa sản phẩm này?')) return;
    try {
      await api.delete(`/products/${id}`);
      addToast('Đã vô hiệu hóa', 'info');
      loadData();
    } catch { addToast('Lỗi', 'error'); }
  };

  const filtered = products.filter(p => p.productName.toLowerCase().includes(search.toLowerCase()));

  if (loading) return <div className="loading"><div className="spinner" /></div>;

  return (
    <div className="page">
      <div className="page-header" style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
        <div><h1>🛍️ Quản lý sản phẩm</h1><p>{products.length} sản phẩm</p></div>
        <button className="btn btn-primary" onClick={openCreate}>+ Thêm sản phẩm</button>
      </div>

      <div className="filter-bar">
        <input className="form-control search-input" placeholder="🔍 Tìm sản phẩm..." value={search} onChange={e => setSearch(e.target.value)} />
      </div>

      <div className="card">
        <div className="table-wrap">
          <table>
            <thead>
              <tr><th>Ảnh</th><th>Tên sản phẩm</th><th>Danh mục</th><th>Giá</th><th>Tồn kho</th><th>Trạng thái</th><th>Hành động</th></tr>
            </thead>
            <tbody>
              {filtered.map(p => (
                <tr key={p.productID}>
                  <td><img src={p.imageUrl} alt="" style={{ width: 40, height: 40, objectFit: 'cover', borderRadius: 6 }} onError={e => e.target.style.display='none'} /></td>
                  <td style={{ fontWeight: 500 }}>{p.productName}</td>
                  <td style={{ color: 'var(--text-muted)' }}>{p.categoryName}</td>
                  <td style={{ fontFamily: 'Syne', fontWeight: 700, color: 'var(--accent)' }}>{formatCurrency(p.price)}</td>
                  <td style={{ fontFamily: 'Syne', fontWeight: 700 }}>{p.inventoryQty ?? p.stockQuantity}</td>
                  <td><span className={`badge badge-${p.status}`}>{p.status === 'active' ? 'Hoạt động' : 'Tắt'}</span></td>
                  <td style={{ display: 'flex', gap: 6 }}>
                    <button className="btn btn-secondary btn-sm" onClick={() => openEdit(p)}>✏️</button>
                    <button className="btn btn-danger btn-sm" onClick={() => deleteProduct(p.productID)}>🗑</button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {modal && (
        <div className="modal-overlay" onClick={() => setModal(null)}>
          <div className="modal" style={{ maxWidth: 520 }} onClick={e => e.stopPropagation()}>
            <div className="modal-header">
              <div className="modal-title">{modal === 'create' ? '+ Thêm sản phẩm' : '✏️ Chỉnh sửa sản phẩm'}</div>
              <button className="modal-close" onClick={() => setModal(null)}>×</button>
            </div>
            {[
              { key: 'productName', label: 'Tên sản phẩm', type: 'text' },
              { key: 'price', label: 'Giá (VNĐ)', type: 'number' },
              { key: 'stockQuantity', label: 'Số lượng tồn kho', type: 'number' },
              { key: 'imageUrl', label: 'URL ảnh', type: 'text' },
            ].map(f => (
              <div className="form-group" key={f.key}>
                <label className="form-label">{f.label}</label>
                <input className="form-control" type={f.type} value={form[f.key]} onChange={e => setForm(p => ({ ...p, [f.key]: e.target.value }))} />
              </div>
            ))}
            <div className="form-group">
              <label className="form-label">Danh mục</label>
              <select className="form-control" value={form.categoryID} onChange={e => setForm(p => ({ ...p, categoryID: e.target.value }))}>
                <option value="">Chọn danh mục</option>
                {categories.map(c => <option key={c.categoryID} value={c.categoryID}>{c.categoryName}</option>)}
              </select>
            </div>
            <div className="form-group">
              <label className="form-label">Mô tả</label>
              <textarea className="form-control" rows={3} value={form.description} onChange={e => setForm(p => ({ ...p, description: e.target.value }))} />
            </div>
            {modal !== 'create' && (
              <div className="form-group">
                <label className="form-label">Trạng thái</label>
                <select className="form-control" value={form.status} onChange={e => setForm(p => ({ ...p, status: e.target.value }))}>
                  <option value="active">Hoạt động</option>
                  <option value="inactive">Tắt</option>
                </select>
              </div>
            )}
            <div className="modal-footer">
              <button className="btn btn-secondary" onClick={() => setModal(null)}>Hủy</button>
              <button className="btn btn-primary" onClick={save}>
                {modal === 'create' ? '+ Tạo sản phẩm' : '💾 Lưu'}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
